echo "COMPLETE DIRECTORY LISTING WITH FILES"
echo "══════════════════════════════════════════════════════════════"
echo ""

# Use find to create a nice tree-like structure
find . -type f -o -type d | grep -v "^\.$" | sort | sed 's|^\./||' | awk '
BEGIN { FS = "/" }
NF == 1 {
    printf "📄 %s\n", $1
    next
}
{
    path = ""
    for (i = 1; i < NF; i++) {
        path = path $i "/"
    }
    # Print directories with proper indentation
    if (prev_path != path && path != "") {
        print ""
    }
    # Print files with indentation
    if ($NF != "") {
        indent = ""
        for (i = 1; i < NF; i++) indent = indent "  "
        printf "%s📄 %s\n", indent, $NF
    }
    prev_path = path
}
' | head -100

echo ""
echo "══════════════════════════════════════════════════════════════"

